import { moduleMetadata } from '@storybook/angular';
import { PfHeaderComponent } from './header.component';
import { PfLogoComponent } from '../logo/logo.component';
import { PfButtonComponent } from '../button/button.component';
import { PfAvatarComponent } from '../avatar/avatar.component';
import { PfTagComponent } from '../tag/tag.component';
const meta = {
    title: 'Composants/Header',
    component: PfHeaderComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Header app-level en 3 zones via slots `[brand]`, `[nav]`, `[actions]`.",
            },
        },
        layout: 'fullscreen',
    },
    decorators: [
        moduleMetadata({
            imports: [
                PfHeaderComponent,
                PfLogoComponent,
                PfButtonComponent,
                PfAvatarComponent,
                PfTagComponent,
            ],
        }),
    ],
};
export default meta;
export const Default = {
    render: () => ({
        template: `
      <pf-header>
        <pf-logo brand title="Polynésie française"></pf-logo>
      </pf-header>
    `,
    }),
};
export const WithSubtitle = {
    render: () => ({
        template: `
      <pf-header>
        <pf-logo brand title="Polynésie française" subtitle="Service en ligne"></pf-logo>
      </pf-header>
    `,
    }),
};
export const WithActions = {
    render: () => ({
        template: `
      <pf-header>
        <pf-logo brand href="/" title="Polynésie française" subtitle="Démarches en ligne"></pf-logo>
        <ng-container actions>
          <pf-button variant="ghost" size="sm">Aide</pf-button>
          <pf-button variant="primary" size="sm">Se connecter</pf-button>
        </ng-container>
      </pf-header>
    `,
    }),
};
export const Authenticated = {
    render: () => ({
        template: `
      <pf-header>
        <pf-logo brand href="/" title="Polynésie française" subtitle="Démarches en ligne"></pf-logo>
        <ng-container actions>
          <pf-tag variant="info">Mode test</pf-tag>
          <pf-avatar alt="Marie Dupont" size="sm"></pf-avatar>
          <pf-button variant="ghost" size="sm">Déconnexion</pf-button>
        </ng-container>
      </pf-header>
    `,
    }),
};
